mapper.update:
UPDATE student
name = #{name}, gender = #{gender}, age = #{age}, class_id = #{classId}, phone = #{phone}, email = #{email}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT s.id, s.name, s.gender, s.age, s.class_id, s.phone, s.email, s.create_time, s.update_time, cr.name AS className, cr.grade, cr.major, cr.homeroom_teacher_id AS homeroomTeacherId FROM student s LEFT JOIN class_room cr ON s.class_id = cr.id
AND s.gender = #{gender}
AND cr.name LIKE CONCAT('%', #{className}, '%')
AND s.name LIKE CONCAT('%', #{name}, '%')
AND cr.major LIKE CONCAT('%', #{major}, '%')
AND s.age = #{age}
